params.default:
    query dashboard($projectName: String, $issueSort: IssueSort = recently_updated, $pullRequestSort: PullRequestSort = created_at_desc) {
  current_user {
    id
    name
    username
    projects_count
    pull_requests_count
    issues_count
    starred_count
    projects(name: $projectName, first: 5) {
      total_count
      nodes { id name path path_with_namespace public }
    }
    issues(first: 5, sort: $issueSort) {
      total_count
      nodes { id ident title show_path updated_at issue_state { title } }
    }
    pull_requests(first: 5, sort: $pullRequestSort) {
      total_count
      nodes { id title show_path updated_at }
    }
  }
}

    query unreadCount {
  current_user {
    unread_count { infos messages referer total }
  }
}
